Greedy insertion with regret-based heuristic: evaluate all feasible assign-cost combinations, select insertion minimizing marginal cost increase, fallback to seed empty assign if none feasible.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount != len(dess) || orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	type Candidate struct {
		assignIdx int
		costDelta float64
		insertOk  bool
	}

	for jj := 0; jj < orderCount; jj++ {
		bestCandidate := Candidate{-1, 1e18, false}

		totalTried := dispatch.AssignsLen + 1
		if totalTried > MAXASSIGNS {
			totalTried = MAXASSIGNS
		}

		for ai := 0; ai < totalTried; ai++ {
			tmpAssign := dispatch.Assigns[ai]

			okBeforeInsert := tmpAssign.Cost >= 0

			success := dispatch.Assigns[ai].AddShip(total_ship+jj, oris[jj], dess[jj])
			if success {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				success = (newCost >= 0)
				if success {
					oldCost := tmpAssign.Cost
					delta := newCost - oldCost
					if !okBeforeInsert {
						delta = newCost
					}
					if delta < bestCandidate.costDelta {
						bestCandidate.assignIdx = ai
						bestCandidate.costDelta = delta
						bestCandidate.insertOk = true
					}
				}

				dispatch.Assigns[ai].RemoveShip(total_ship + jj)
				dispatch.Assigns[ai].GenRoute()
			}
		}

		if bestCandidate.insertOk {
			targetIdx := bestCandidate.assignIdx
			dispatch.Assigns[targetIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[targetIdx].GenRoute()
			if targetIdx >= dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.AssignsLen++
			}
		} else {
			fallbackIdx := -1
			for fi := 0; fi < MAXASSIGNS; fi++ {
				if fi >= dispatch.AssignsLen {
					fallbackIdx = fi
					break
				}
				if dispatch.Assigns[fi].StationsLen == 0 {
					fallbackIdx = fi
					break
				}
			}

			if fallbackIdx >= 0 {
				ok := dispatch.Assigns[fallbackIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						if fallbackIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen = fallbackIdx + 1
						}
						continue
					}
				}
				dispatch.Assigns[fallbackIdx].RemoveShip(total_ship + jj)
				dispatch.Assigns[fallbackIdx].GenRoute()
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

